const items = $input.all();
const list = items[0].json.list || [];

if (list.length === 0) {
  return [{ json: { skip: true } }];
}

const lines = list.map((c, i) => {
  const name = `${c.fp_last_name}${c.fp_first_name}` || '（名前未取得）';
  const statusLabel = {
    confirmed: '✅ 面談日確定済み',
    waiting: '⏳ マッチング済み・連絡待ち',
    not_contacted: '❌ FP未連絡',
    unknown: '⚠️ 要確認'
  }[c.fp_status] || c.fp_status;

  return `${i + 1}. ${c.hitomono_id} ${name}様\n   ${statusLabel}`;
}).join('\n\n');

const message = `📋 本日の後確リスト（${list.length}件）\n${new Date().toLocaleDateString('ja-JP', {month:'long',day:'numeric',weekday:'short'})}\n\n${lines}\n\n▼ 電話後はこちらで結果入力\nhttps://bo-dashboard.vercel.app`;

return [{ json: { message, list } }];
